#include <bits/stdc++.h>
using namespace std;

const int N=1010,INF=0x3f3f3f3f;

struct Node{
    int idx,val;
};

bool operator<(Node x,Node y){
    return x.val>y.val;
}

int n,m,dis[N*25],c[N],st;
int head[N*25],ver[N*25*25],edge[N*25*25],nxt[N*25*25],tot;
bool b[N*25];

int cal(int x,int y){
    return (x-1)*m+y;
}

void add(int x,int y,int z){
    ver[++tot]=y,edge[tot]=z,nxt[tot]=head[x],head[x]=tot;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        scanf("%d",&c[i]);
        if(!c[i])
            st=i;
    }
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            for(int k=1;k<=m;k++)
                if(0<i+c[k] && i+c[k]<=n)
                    add(cal(i,j),cal(i+c[k],k),abs(c[k])*2+abs(j-k));
    memset(dis,0x3f,sizeof(dis));
    dis[cal(1,st)]=0;
    priority_queue<Node> q;
    q.push({cal(1,st),0});
    while(q.size()){
        while(q.size() && b[q.top().idx])
            q.pop();
        if(q.empty())
            break;
        int x=q.top().idx;
        q.pop(),b[x]=1;
        for(int i=head[x],y;i;i=nxt[i]){
            y=ver[i];
            if(dis[y]>dis[x]+edge[i]){
                dis[y]=dis[x]+edge[i];
                q.push({y,dis[y]});
            }
        }
    }
    int ans=INF;
    for(int i=1;i<=m;i++)
        ans=min(ans,dis[cal(n,i)]);
    if(ans==INF)
        printf("-1");
    else
        printf("%d",ans);
    return 0;
}
